#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll> a(n,0);        for(int i=0;i<n;i++){            cin>>a[i];        }        bool flag=false;        for(int i=0;i<n;i++){            for(int j=i+1;j<min(n,i+100);j++){                if((a[j]%a[i])%2==0){                    cout<<a[i]<<" "<<a[j]<<endl;                    flag=true;                    break;                }            }            if(flag){                break;            }        }        if(!flag){            cout<<-1<<endl;        }    }}